#include "interface.h"
#include "roaring.h"
#include <vector>

uint64_t many_union_cardinality(
    const std::vector<uint32_t>& offsets,
    const std::vector<uint32_t>& values) {
  if (offsets.size() <= 1) return 0;

  size_t num_shards = offsets.size() - 1;
  std::vector<roaring_bitmap_t*> bitmaps(num_shards);

  for (size_t i = 0; i < num_shards; ++i) {
    uint32_t start = offsets[i];
    uint32_t end = offsets[i + 1];
    if (start < end) {
      bitmaps[i] = roaring_bitmap_from_range(start, end, 1);
      // Since the input is sorted, we can use roaring_bitmap_add_many for efficiency
      // However, roaring_bitmap_from_range is not applicable here as values are not necessarily contiguous.
      // We use roaring_bitmap_add_many on the slice.
      roaring_bitmap_t* bm = roaring_bitmap_create();
      roaring_bitmap_add_many(bm, end - start, &values[start]);
      bitmaps[i] = bm;
    } else {
      bitmaps[i] = roaring_bitmap_create();
    }
  }

  roaring_bitmap_t* result = roaring_bitmap_or_many(num_shards, bitmaps.data());
  uint64_t cardinality = roaring_bitmap_get_cardinality(result);

  roaring_bitmap_free(result);
  for (size_t i = 0; i < num_shards; ++i) {
    roaring_bitmap_free(bitmaps[i]);
  }

  return cardinality;
}
